     9→const path = require('path');
    10→const glob = require('glob');
    11→const events = require('events');
    12→const mocha = require('mocha');
    13→const createStatsCollector = require('mocha/lib/stats-collector');
    14→const MochaJUnitReporter = require('mocha-junit-reporter');
    15→const url = require('url');
    16→const minimatch = require('minimatch');
    17→const fs = require('fs');
    18→const playwright = require('@playwright/test');
    19→const { applyReporter } = require('../reporter');
    20→const yaserver = require('yaserver');
    21→const http = require('http');
    22→const { randomBytes } = require('crypto');
    23→const minimist = require('minimist');
    24→const { promisify } = require('node:util');
    25→
    26→/**
    27→ * @type {{
    28→ * run: string;
    29→ * grep: string;
    30→ * runGlob: string;
    31→ * browser: string;
    32→ * reporter: string;
    33→ * 'reporter-options': string;
    34→ * tfs: string;
    35→ * build: boolean;
    36→ * debug: boolean;
    37→ * sequential: boolean;
    38→ * help: boolean;
    39→ * }}
    40→*/
    41→const args = minimist(process.argv.slice(2), {
    42→	boolean: ['build', 'debug', 'sequential', 'help'],
    43→	string: ['run', 'grep', 'runGlob', 'browser', 'reporter', 'reporter-options', 'tfs'],
    44→	default: {
    45→		build: false,
    46→		browser: ['chromium', 'firefox', 'webkit'],
    47→		reporter: process.platform === 'win32' ? 'list' : 'spec',
    48→		'reporter-options': ''
    49→	},
    50→	alias: {
    51→		grep: ['g', 'f'],
    52→		runGlob: ['glob', 'runGrep'],
    53→		debug: ['debug-browser'],
    54→		help: 'h'
    55→	},
    56→	describe: {
    57→		build: 'run with build output (out-build)',
    58→		run: 'only run tests matching <relative_file_path>',
    59→		grep: 'only run tests matching <pattern>',
    60→		debug: 'do not run browsers headless',
    61→		sequential: 'only run suites for a single browser at a time',
    62→		browser: 'browsers in which tests should run',
    63→		reporter: 'the mocha reporter',
    64→		'reporter-options': 'the mocha reporter options',
    65→		tfs: 'tfs',
    66→		help: 'show the help'
    67→	}
    68→});
    69→
    70→if (args.help) {
    71→	console.log(`Usage: node ${process.argv[1]} [options]
    72→
    73→Options:
    74→--build              run with build output (out-build)
    75→--run <relative_file_path> only run tests matching <relative_file_path>
    76→--grep, -g, -f <pattern> only run tests matching <pattern>
    77→--debug, --debug-browser do not run browsers headless
    78→--sequential         only run suites for a single browser at a time
    79→--browser <browser>  browsers in which tests should run
    80→--reporter <reporter> the mocha reporter
    81→--reporter-options <reporter-options> the mocha reporter options
    82→--tfs <tfs>          tfs
    83→--help, -h           show the help`);
    84→	process.exit(0);
    85→}
    86→
    87→const isDebug = !!args.debug;
    88→
    89→const withReporter = (function () {
    90→	if (args.tfs) {
    91→		{
    92→			return (browserType, runner) => {
    93→				new mocha.reporters.Spec(runner);
    94→				new MochaJUnitReporter(runner, {
    95→					reporterOptions: {
    96→						testsuitesTitle: `${args.tfs} ${process.platform}`,
    97→						mochaFile: process.env.BUILD_ARTIFACTSTAGINGDIRECTORY ? path.join(process.env.BUILD_ARTIFACTSTAGINGDIRECTORY, `test-results/${process.platform}-${process.arch}-${browserType}-${args.tfs.toLowerCase().replace(/[^\w]/g, '-')}-results.xml`) : undefined
    98→					}
    99→				});
   100→			};
   101→		}
   102→	} else {
   103→		return (_, runner) => applyReporter(runner, args);
   104→	}
   105→})();
   106→
   107→const outdir = args.build ? 'out-build' : 'out';
   108→const rootDir = path.resolve(__dirname, '..', '..', '..');
   109→const out = path.join(rootDir, `${outdir}`);
   110→
   111→function ensureIsArray(a) {
   112→	return Array.isArray(a) ? a : [a];
   113→}
   114→
   115→const testModules = (async function () {
   116→
   117→	const excludeGlob = '**/{node,electron-sandbox,electron-main,electron-utility}/**/*.test.js';
   118→	let isDefaultModules = true;
   119→	let promise;
   120→
   121→	if (args.run) {
   122→		// use file list (--run)
   123→		isDefaultModules = false;
   124→		promise = Promise.resolve(ensureIsArray(args.run).map(file => {
   125→			file = file.replace(/^src/, 'out');
   126→			file = file.replace(/\.ts$/, '.js');
   127→			return path.relative(out, file);
   128→		}));
   129→
   130→	} else {
   131→		// glob patterns (--glob)
   132→		const defaultGlob = '**/*.test.js';
   133→		const pattern = args.runGlob || defaultGlob;
   134→		isDefaultModules = pattern === defaultGlob;
   135→
   136→		promise = new Promise((resolve, reject) => {
   137→			glob(pattern, { cwd: out }, (err, files) => {
   138→				if (err) {
   139→					reject(err);
   140→				} else {
   141→					resolve(files);
   142→				}
   143→			});
   144→		});
   145→	}
   146→
   147→	return promise.then(files => {
   148→		const modules = [];
   149→		for (const file of files) {
   150→			if (!minimatch(file, excludeGlob)) {
   151→				modules.push(file.replace(/\.js$/, ''));
   152→
   153→			} else if (!isDefaultModules) {
   154→				console.warn(`DROPPONG ${file} because it cannot be run inside a browser`);
   155→			}
   156→		}
   157→		return modules;
   158→	});
   159→})();
   160→
   161→function consoleLogFn(msg) {
   162→	const type = msg.type();
   163→	const candidate = console[type];
   164→	if (candidate) {
   165→		return candidate;
   166→	}
   167→
   168→	if (type === 'warning') {
   169→		return console.warn;
   170→	}
   171→
   172→	return console.log;
   173→}
