   216→				return remoteMethod(request, response, p => fs.promises.readFile(massagePath(p), 'utf-8'));
   217→			case '/remoteMethod/__writeFileInTests':
   218→				return remoteMethod(request, response, (p, contents) => fs.promises.writeFile(massagePath(p), contents));
   219→			case '/remoteMethod/__readDirInTests':
   220→				return remoteMethod(request, response, p => fs.promises.readdir(massagePath(p)));
   221→			case '/remoteMethod/__unlinkInTests':
   222→				return remoteMethod(request, response, p => fs.promises.unlink(massagePath(p)));
   223→			case '/remoteMethod/__mkdirPInTests':
   224→				return remoteMethod(request, response, p => fs.promises.mkdir(massagePath(p), { recursive: true }));
   225→			default:
   226→				return serveStatic.handle(request, response);
   227→		}
   228→	});
   229→
   230→	return new Promise((resolve, reject) => {
   231→		server.listen(0, 'localhost', () => {
   232→			resolve({
   233→				dispose: () => server.close(),
   234→				// @ts-ignore
   235→				url: `http://localhost:${server.address().port}${prefix}`
   236→			});
   237→		});
   238→		server.on('error', reject);
   239→	});
   240→}
   241→
   242→async function runTestsInBrowser(testModules, browserType) {
   243→	const server = await createServer();
   244→	const browser = await playwright[browserType].launch({ headless: !Boolean(args.debug), devtools: Boolean(args.debug) });
   245→	const context = await browser.newContext();
   246→	const page = await context.newPage();
   247→	const target = new URL(server.url + '/test/unit/browser/renderer.html');
   248→	target.searchParams.set('baseUrl', url.pathToFileURL(path.join(rootDir, 'src')).toString());
   249→	if (args.build) {
   250→		target.searchParams.set('build', 'true');
   251→	}
   252→	if (process.env.BUILD_ARTIFACTSTAGINGDIRECTORY) {
   253→		target.searchParams.set('ci', 'true');
   254→	}
   255→
   256→	// append CSS modules as query-param
   257→	await promisify(require('glob'))('**/*.css', { cwd: out }).then(async cssModules => {
   258→		const cssData = await new Response((await new Response(cssModules.join(',')).blob()).stream().pipeThrough(new CompressionStream('gzip'))).arrayBuffer();
   259→		target.searchParams.set('_devCssData', Buffer.from(cssData).toString('base64'));
   260→	});
   261→
   262→	const emitter = new events.EventEmitter();
   263→	await page.exposeFunction('mocha_report', (type, data1, data2) => {
   264→		emitter.emit(type, data1, data2);
   265→	});
   266→
   267→	await page.goto(target.href);
   268→
   269→	if (args.build) {
   270→		const nlsMessages = await fs.promises.readFile(path.join(out, 'nls.messages.json'), 'utf8');
   271→		await page.evaluate(value => {
   272→			// when running from `out-build`, ensure to load the default
   273→			// messages file, because all `nls.localize` calls have their
   274→			// english values removed and replaced by an index.
   275→			// @ts-ignore
   276→			globalThis._VSCODE_NLS_MESSAGES = JSON.parse(value);
   277→		}, nlsMessages);
   278→	}
   279→
   280→	page.on('console', async msg => {
   281→		consoleLogFn(msg)(msg.text(), await Promise.all(msg.args().map(async arg => await arg.jsonValue())));
   282→	});
   283→
   284→	withReporter(browserType, new EchoRunner(emitter, browserType.toUpperCase()));
   285→
   286→	// collection failures for console printing
   287→	const failingModuleIds = [];
   288→	const failingTests = [];
   289→	emitter.on('fail', (test, err) => {
   290→		failingTests.push({ title: test.fullTitle, message: err.message });
   291→
   292→		if (err.stack) {
   293→			const regex = /(vs\/.*\.test)\.js/;
   294→			for (const line of String(err.stack).split('\n')) {
   295→				const match = regex.exec(line);
   296→				if (match) {
   297→					failingModuleIds.push(match[1]);
   298→					return;
   299→				}
   300→			}
   301→		}
   302→	});
   303→
   304→	try {
   305→		// @ts-expect-error
   306→		await page.evaluate(opts => loadAndRun(opts), {
   307→			modules: testModules,
   308→			grep: args.grep,
   309→		});
   310→	} catch (err) {
   311→		console.error(err);
   312→	}
   313→	if (!isDebug) {
   314→		server?.dispose();
   315→		await browser.close();
   316→	}
   317→
   318→	if (failingTests.length > 0) {
   319→		let res = `The followings tests are failing:\n - ${failingTests.map(({ title, message }) => `${title} (reason: ${message})`).join('\n - ')}`;
   320→
   321→		if (failingModuleIds.length > 0) {
   322→			res += `\n\nTo DEBUG, open ${browserType.toUpperCase()} and navigate to ${target.href}?${failingModuleIds.map(module => `m=${module}`).join('&')}`;
   323→		}
   324→
   325→		return `${res}\n`;
   326→	}
   327→}
   328→
   329→class EchoRunner extends events.EventEmitter {
   330→
   331→	constructor(event, title = '') {
   332→		super();
   333→		createStatsCollector(this);
   334→		event.on('start', () => this.emit('start'));
   335→		event.on('end', () => this.emit('end'));
   336→		event.on('suite', (suite) => this.emit('suite', EchoRunner.deserializeSuite(suite, title)));
   337→		event.on('suite end', (suite) => this.emit('suite end', EchoRunner.deserializeSuite(suite, title)));
   338→		event.on('test', (test) => this.emit('test', EchoRunner.deserializeRunnable(test)));
   339→		event.on('test end', (test) => this.emit('test end', EchoRunner.deserializeRunnable(test)));
   340→		event.on('hook', (hook) => this.emit('hook', EchoRunner.deserializeRunnable(hook)));
   341→		event.on('hook end', (hook) => this.emit('hook end', EchoRunner.deserializeRunnable(hook)));
   342→		event.on('pass', (test) => this.emit('pass', EchoRunner.deserializeRunnable(test)));
   343→		event.on('fail', (test, err) => this.emit('fail', EchoRunner.deserializeRunnable(test, title), EchoRunner.deserializeError(err)));
   344→		event.on('pending', (test) => this.emit('pending', EchoRunner.deserializeRunnable(test)));
   345→	}
   346→
   347→	static deserializeSuite(suite, titleExtra) {
   348→		return {
   349→			root: suite.root,
   350→			suites: suite.suites,
   351→			tests: suite.tests,
   352→			title: titleExtra && suite.title ? `${suite.title} - /${titleExtra}/` : suite.title,
   353→			titlePath: () => suite.titlePath,
   354→			fullTitle: () => suite.fullTitle,
   355→			timeout: () => suite.timeout,
   356→			retries: () => suite.retries,
   357→			slow: () => suite.slow,
   358→			bail: () => suite.bail
   359→		};
   360→	}
   361→
   362→	static deserializeRunnable(runnable, titleExtra) {
   363→		return {
   364→			title: runnable.title,
   365→			fullTitle: () => titleExtra && runnable.fullTitle ? `${runnable.fullTitle} - /${titleExtra}/` : runnable.fullTitle,
   366→			titlePath: () => runnable.titlePath,
   367→			async: runnable.async,
   368→			slow: () => runnable.slow,
   369→			speed: runnable.speed,
   370→			duration: runnable.duration,
   371→			currentRetry: () => runnable.currentRetry,
   372→		};
   373→	}
   374→
   375→	static deserializeError(err) {
   376→		const inspect = err.inspect;
   377→		err.inspect = () => inspect;
   378→		return err;
   379→	}
   380→}
   381→
   382→testModules.then(async modules => {
   383→
   384→	// run tests in selected browsers
   385→	const browserTypes = Array.isArray(args.browser)
   386→		? args.browser : [args.browser];
   387→
   388→	let messages = [];
   389→	let didFail = false;
   390→
   391→	try {
   392→		if (args.sequential) {
   393→			for (const browserType of browserTypes) {
   394→				messages.push(await runTestsInBrowser(modules, browserType));
   395→			}
   396→		} else {
   397→			messages = await Promise.all(browserTypes.map(async browserType => {
   398→				return await runTestsInBrowser(modules, browserType);
   399→			}));
   400→		}
   401→	} catch (err) {
   402→		console.error(err);
   403→		if (!isDebug) {
   404→			process.exit(1);
   405→		}
   406→	}
   407→
   408→	// aftermath
   409→	for (const msg of messages) {
   410→		if (msg) {
   411→			didFail = true;
   412→			console.log(msg);
   413→		}
   414→	}
   415→	if (!isDebug) {
   416→		process.exit(didFail ? 1 : 0);
   417→	}
   418→
   419→}).catch(err => {
   420→	console.error(err);
   421→});
   422→

