   256→		@IExtHostFileSystemInfo private readonly _fileSystemInfoService: IExtHostFileSystemInfo,
   257→		private readonly _extHostDocumentsAndEditors: ExtHostDocumentsAndEditors,
   258→	) {
   259→		this._proxy = mainContext.getProxy(MainContext.MainThreadDiagnostics);
   260→	}
   261→
   262→	createDiagnosticCollection(extensionId: ExtensionIdentifier, name?: string): vscode.DiagnosticCollection {
