   269→				_logService.trace('[DiagnosticCollection] change many (extension, owner, uris)', extensionId.value, owner, entries.length === 0 ? 'CLEARING' : entries);
   270→			}
   271→			$clear(owner: string): void {
   272→				_proxy.$clear(owner);
   273→				_logService.trace('[DiagnosticCollection] remove all (extension, owner)', extensionId.value, owner);
   274→			}
   275→			dispose(): void {
   276→				_proxy.dispose();
   277→			}
   278→		};
   279→
   280→
   281→		let owner: string;
   282→		if (!name) {
   283→			name = '_generated_diagnostic_collection_name_#' + ExtHostDiagnostics._idPool++;
   284→			owner = name;
